from __future__ import annotations

import json
from pathlib import Path
from typing import Any

from src.advanced.device_path import get_data_path_read, get_data_path_write


def load_settings(mac_clean: str) -> dict[str, Any] | None:
    """加载设备保存的设置。

    Args:
        mac_clean: MAC地址（无分隔符，小写）

    Returns:
        dict: 设备设置，或 None 如果不存在
    """
    path = get_data_path_read(None, mac_clean, 'settings')
    if path and path.exists():
        try:
            with open(path, 'r', encoding='utf-8') as f:
                return json.load(f)
        except Exception:
            return None
    return None


def save_settings(mac_clean: str, settings: dict[str, Any]) -> bool:
    """保存设备设置。

    Args:
        mac_clean: MAC地址（无分隔符，小写）
        settings: 要保存的设置

    Returns:
        bool: 是否保存成功
    """
    from datetime import datetime, timezone

    # 合并现有设置
    existing = load_settings(mac_clean) or {}
    existing.update(settings)
    existing['last_updated'] = datetime.now(timezone.utc).isoformat()

    path = get_data_path_write(None, mac_clean, 'settings')
    try:
        with open(path, 'w', encoding='utf-8') as f:
            json.dump(existing, f, indent=2, ensure_ascii=False)
        return True
    except Exception:
        return False
