// v8.43: 三段式开关 - 更新高亮
function updateSwitchHighlight(switchId, selectedValue) {
    var switchEl = document.getElementById(switchId);
    if (!switchEl) return;
    var buttons = switchEl.querySelectorAll('.ts-btn');
    buttons.forEach(function(btn) {
        if (btn.dataset.value === selectedValue) {
            btn.classList.add('active');
        } else {
            btn.classList.remove('active');
        }
    });
}

// v8.43: 设置日夜模式
function setDayNightMode(mode) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPost('/api/v1/ptz/' + dev + '/image/filter', { dayNightMode: mode })
        .then(function(r) {
            if (r && r.success) {
                showToast('success', '日夜模式: ' + mode);
                if (typeof operationLog === 'function') operationLog('日夜模式: ' + mode, 'success');
                updateSwitchHighlight('dayNightSwitch', mode);
            }
        });
}

