// v8.47: 恢复保存的设置 - 设置DOM值并调用API应用到设备
function restoreSettings(deviceIp) {
    apiGet('/api/v1/ptz/' + deviceIp + '/image/settings-saved').then(function(r) {
        if (r && r.success && r.data && Object.keys(r.data).length > 0) {
            var s = r.data;
            // 恢复白平衡
            if (s.whitebalance && s.whitebalance.mode) {
                var wbMode = document.getElementById('wbMode');
                if (wbMode) {
                    wbMode.value = s.whitebalance.mode;
                    onWbModeChange(s.whitebalance.mode); // 会调用setWhiteBalanceMode API
                }
                // 恢复R/B增益
                if (s.whitebalance.red_gain !== undefined) {
                    var wbRed = document.getElementById('wbRed');
                    if (wbRed) {
                        wbRed.value = s.whitebalance.red_gain;
                        setWhiteBalanceGain('red', s.whitebalance.red_gain);
                    }
                }
                if (s.whitebalance.blue_gain !== undefined) {
                    var wbBlue = document.getElementById('wbBlue');
                    if (wbBlue) {
                        wbBlue.value = s.whitebalance.blue_gain;
                        setWhiteBalanceGain('blue', s.whitebalance.blue_gain);
                    }
                }
            }
            // 恢复降噪
            if (s.noisereduce) {
                var dnrSpatial = document.getElementById('dnrSpatial');
                var dnrTemporal = document.getElementById('dnrTemporal');
                if (dnrSpatial && s.noisereduce.spatial_level !== undefined) {
                    dnrSpatial.value = s.noisereduce.spatial_level;
                    setNoiseReduce('spatial', s.noisereduce.spatial_level);
                }
                if (dnrTemporal && s.noisereduce.temporal_level !== undefined) {
                    dnrTemporal.value = s.noisereduce.temporal_level;
                    setNoiseReduce('temporal', s.noisereduce.temporal_level);
                }
            }
            // 恢复慢快门
            if (s.slow_shutter && s.slow_shutter.dss_level) {
                var ssSelect = document.getElementById('slowShutterSelect');
                if (ssSelect) {
                    ssSelect.value = s.slow_shutter.dss_level;
                    onSlowShutterChange(s.slow_shutter.dss_level); // 会调用API
                }
            }
            // 恢复快门
            if (s.shutter && s.shutter.level) {
                var shutterSelect = document.getElementById('shutterSpeed');
                if (shutterSelect) {
                    shutterSelect.value = s.shutter.level;
                    setShutter(s.shutter.level);
                }
            }
            // 恢复光圈
            if (s.iris && s.iris.level) {
                var irisSelect = document.getElementById('irisLevel');
                if (irisSelect) {
                    irisSelect.value = s.iris.level;
                    setIris(s.iris.level);
                }
            }
            // 恢复曝光模式
            if (s.exposure && s.exposure.mode) {
                var exposureSelect = document.getElementById('exposureMode');
                if (exposureSelect) {
                    exposureSelect.value = s.exposure.mode;
                    setExposureMode(s.exposure.mode);
                }
            }
            // 恢复锐度
            if (s.sharpness && s.sharpness.level !== undefined) {
                var sharpnessInput = document.getElementById('sharpness');
                if (sharpnessInput) {
                    sharpnessInput.value = s.sharpness.level;
                    setSharpness(s.sharpness.level);
                }
            }
            // 恢复画面设置（亮度/对比度/饱和度）
            if (s.image_settings) {
                var brightness = document.getElementById('brightness');
                var contrast = document.getElementById('contrast');
                var saturation = document.getElementById('saturation');
                if (brightness && s.image_settings.brightness !== undefined) {
                    brightness.value = s.image_settings.brightness;
                }
                if (contrast && s.image_settings.contrast !== undefined) {
                    contrast.value = s.image_settings.contrast;
                }
                if (saturation && s.image_settings.saturation !== undefined) {
                    saturation.value = s.image_settings.saturation;
                }
                // 调用API一次性更新
                var imgData = {};
                if (s.image_settings.brightness !== undefined) imgData.brightness = s.image_settings.brightness;
                if (s.image_settings.contrast !== undefined) imgData.contrast = s.image_settings.contrast;
                if (s.image_settings.saturation !== undefined) imgData.saturation = s.image_settings.saturation;
                apiPut('/api/v1/ptz/' + deviceIp + '/image/settings', imgData);
            }
        }
    });
}

